using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – success scenarios

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 9.99m, 2));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.HasCount(1, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalCorrectly()
    {
        // Arrange
        var items = CreateItems(("A", 10m, 1), ("B", 5m, 3));

        // Act
        var order = _service.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(25m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_SetsNonEmptyIdAndCreatedAt()
    {
        var before = DateTime.UtcNow;
        var order = _service.CreateOrder("cust-1", CreateItems(("X", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsNotNull(order.Id);
        Assert.IsTrue(order.Id.Length > 0, "Id should not be empty");
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            "CreatedAt should be within the test execution window");
    }

    #endregion

    #region CreateOrder – validation / error scenarios

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateItems(("X", 1m, 1))));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems(("X", 5m, 1)));

        var fetched = _service.GetOrder(created.Id);

        Assert.IsNotNull(fetched);
        Assert.AreSame(created, fetched);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        _service.CreateOrder("cust-A", CreateItems(("X", 1m, 1)));
        _service.CreateOrder("cust-A", CreateItems(("Y", 2m, 1)));
        _service.CreateOrder("cust-B", CreateItems(("Z", 3m, 1)));

        var result = _service.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(result);
    }

    #endregion

    #region Data-driven edge cases

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_VariousPricesAndQuantities_CalculatesCorrectTotal(
        decimal price, int quantity, decimal expectedTotal)
    {
        var items = CreateItems(("Product", price, quantity));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(decimal price, int quantity, decimal expectedTotal)> TotalCalculationData =>
    [
        (0m, 5, 0m),
        (10.50m, 1, 10.50m),
        (3.33m, 3, 9.99m),
        (100m, 10, 1000m),
    ];

    #endregion
}

